INSERT INTO `v1_372d63fbd9521d18ff3822bb100fe1cd5cd49a1098718bdd6ad5cbdbedffc78c` VALUES (0.625, 6, 11601, 1, "ツムギ・オンステージ！ツムギがキャップのステージでかわいく\nポーズを決めている。どこでも好きな場所に気軽に飾ることが可\n能。", "ツムギのボトルキャップ", 0.75);
INSERT INTO `v1_372d63fbd9521d18ff3822bb100fe1cd5cd49a1098718bdd6ad5cbdbedffc78c` VALUES (0.625, 6, 11602, 1, "サマー衣装のツムギが、キャップでオンステージ！涼しげな衣装を\nまとい、熱いステージを繰り広げた彼女の勇姿を思い出すことがで\nきる。", "ツムギのサマーボトルキャップ", 0.75);
INSERT INTO `v1_372d63fbd9521d18ff3822bb100fe1cd5cd49a1098718bdd6ad5cbdbedffc78c` VALUES (0.625, 6, 11603, 1, "ノゾミ・オンステージ！ノゾミがキャップのステージでかわいく\nポーズを決めている。どこでも好きな場所に気軽に飾ることが可\n能。", "ノゾミのボトルキャップ", 0.75);
