INSERT INTO `v1_372d63fbd9521d18ff3822bb100fe1cd5cd49a1098718bdd6ad5cbdbedffc78c` VALUES (0.890625, 4, 11701, 1, "ツムギのキーホルダーサイズのタペストリー。どこにでも飾れる\nうえに、身につけてお出掛けもできてしまう万能な一品。", "ツムギのミニタペストリー", 0.8828125);
